<?php
namespace App\Http\Controllers\CommandCenter\Crm; use App\Enums\Crm\ProformaStatus; use App\Http\Controllers\Controller; use App\Http\Requests\Crm\StoreProformaPaymentRequest; use App\Http\Requests\Crm\StoreProformaRequest; use App\Models\Crm\CrmCustomer; use App\Models\Crm\CrmProformaInvoice; use App\Models\Crm\CrmQuotation; use App\Repositories\Crm\CrmCustomerRepository; use App\Repositories\Crm\ProformaRepository; use App\Repositories\Crm\QuotationRepository; use App\Services\Crm\ProformaPdfService; use App\Services\Crm\ProformaService; use Illuminate\Http\RedirectResponse; use Illuminate\Http\Request; use Illuminate\Http\Response; use Illuminate\View\View;
class ProformaController extends Controller { public function index(Request $r,ProformaRepository $p):View{return view('command-center.crm.proformas.index',['proformas'=>$p->paginate($r->user(),$r->only('search','status')),'statuses'=>ProformaStatus::cases()]);} public function createFromQuotation(Request $r,QuotationRepository $q,int $quotation):View{$x=$q->findForUser($r->user(),$quotation);abort_unless($x->status?->value==='accepted',422);return $this->form($x->lead_id,$x->crmCustomer?->id,$x);} public function createFromCustomer(Request $r,CrmCustomerRepository $c,int $customer):View{$x=$c->findForUser($r->user(),$customer);$q=$x->quotation?:new CrmQuotation(['customer_name'=>$x->display_name,'customer_company'=>$x->company_name,'customer_email'=>$x->email,'customer_phone'=>$x->phone,'billing_address'=>$x->billing_address,'currency'=>'INR']);return $this->form($x->lead_id,$x->id,$q);} public function store(StoreProformaRequest $r,ProformaService $s):RedirectResponse{$p=$s->create($r->user(),$r->validated(),$r->integer('lead_id')?:null,$r->integer('customer_id')?:null,$r->integer('quotation_id')?:null);return redirect()->route('crm.proformas.show',$p)->with('status','Proforma invoice created.');} public function show(Request $r,ProformaRepository $p,int $proforma):View{return view('command-center.crm.proformas.show',['proforma'=>$p->find($r->user(),$proforma)]);} public function payment(StoreProformaPaymentRequest $r,ProformaRepository $p,ProformaService $s,int $proforma):RedirectResponse{$s->payment($p->find($r->user(),$proforma),$r->user(),$r->validated());return back()->with('status','Payment recorded.');} public function sent(Request $r,ProformaRepository $p,ProformaService $s,int $proforma):RedirectResponse{$s->markSent($p->find($r->user(),$proforma),$r->user());return back()->with('status','Proforma marked as sent.');} public function link(Request $r,ProformaRepository $p,ProformaService $s,int $proforma):RedirectResponse{$s->link($p->find($r->user(),$proforma),$r->user(),$r->boolean('regenerate'));return back()->with('status','Secure public link ready.');} public function pdf(Request $r,ProformaRepository $p,ProformaPdfService $pdf,int $proforma):Response{$x=$p->find($r->user(),$proforma);return $pdf->document($x)->download($pdf->filename($x));} public function preview(Request $r,ProformaRepository $p,ProformaPdfService $pdf,int $proforma):Response{$x=$p->find($r->user(),$proforma);return $pdf->document($x)->stream($pdf->filename($x));} private function form(?int $leadId,?int $customerId,?CrmQuotation $q):View{$items=$q?->items->map(fn($i)=>$i->only(['name','description','quantity','unit_price','discount_amount','tax_rate']))->all()??[['name'=>'','quantity'=>1,'unit_price'=>0,'discount_amount'=>0,'tax_rate'=>0]];return view('command-center.crm.proformas.form',['quotation'=>$q,'items'=>$items,'leadId'=>$leadId,'customerId'=>$customerId]);} }
